define('guided-tour-floater', ['jquery', 'guided-tour-utils'], function($, utils) {
  const guidedTourFloaterTemplate = `<div class="guided-tour-floater draggable">
    <div class="header">
      <div class="top-bar">
        <span class="icon fa fa-compass"></span>
        <div class="title">Guided Tours</div>
        <div class="right-group">
          <button id="floater-options"><span class="fa fa-cog"></span></button>
          <button id="floater-close"><i class="fa-solid fa-x"></i></button>
        </div>
      </div>
      <div class="completeness">
        <div class="completeness-progress"></div>
      </div>
    </div>
    <div class="guides-content">
      <div class="guides-container">
        <!-- FIXME: There should be a better grouping style here, groups shouldn't be sections. -->
      </div>
      <section class="useful-link">Useful link 1</section>
      <section class="useful-link">Useful link 2</section>
    </div>
  </div>`;

  // Create floater. Bind Events.
  $(guidedTourFloaterTemplate).appendTo($(document.body));

  // Helper to bind click events, TODO: could be deleted.
  function bindFloaterClickEvent(selector, callback) {
    $('.guided-tour-floater ' + selector).on('click', (event) => {
      callback(event);
    });
  };

  bindFloaterClickEvent('.top-bar', (event) => {
    window.localStorage.setItem('TourFloaterCollapsed', document.querySelector('.guided-tour-floater').classList.toggle('collapsed'));
  });

  bindFloaterClickEvent('#floater-close', (event) => {
    if (event.target.closest('.guided-tour-floater').classList.contains('collapsed')) {
      event.target.closest('.guided-tour-floater').remove();
      // window.localStorage.setItem('TourFloaterCollapsed', 'hidden') // Commented to not disable the floater completely, permanently.
      event.stopPropagation();
      // TODO: Or just hide it, and set some cookie/option to not load the javascript code at all the next time.
    }
  });

  bindFloaterClickEvent('#floater-options', (event) => {
    event.stopPropagation();
    console.info('Opened settings menu');
  });

  // Load localStorage state.
  if (window.localStorage.getItem('TourFloaterCollapsed') == 'true') {
    document.querySelector('.guided-tour-floater').classList.add('collapsed');
  }
  if (window.localStorage.getItem('guided-tour-floater-position-x')) {
    // FIXME: Could be XSS i think, if someone edits this key. But that's how the right side panel works too.
    // FIXME: Clamp the allowed values, so the floater is always visible on the screen. Maybe set the value as percentage of screen width? In the dragging functions I mean.
    document.querySelector('.guided-tour-floater').style.left = window.localStorage.getItem('guided-tour-floater-position-x');
  }

  // Definitions.
  /*
   * Function to set up a draggable element, for the floater.
   * Taken from https://www.w3schools.com/howto/howto_js_draggable.asp
   */
  function dragElement(elmnt) {
    console.debug(elmnt)
    if (!elmnt.classList.contains('draggable')) {
      return;
    }
    var pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;
    // otherwise, move the DIV from anywhere inside the DIV:
    elmnt.onmousedown = dragMouseDown;

    function dragMouseDown(e) {
      e = e || window.event;
      e.preventDefault();
      e.stopPropagation();
      e.stopImmediatePropagation();
      // get the mouse cursor position at startup:
      pos3 = e.clientX;
      pos4 = e.clientY;
      document.onmouseup = closeDragElement;
      // call a function whenever the cursor moves:
      document.onmousemove = elementDrag;
    }

    function elementDrag(e) {
      e = e || window.event;
      e.preventDefault();
      e.stopPropagation();
      e.stopImmediatePropagation();
      document.body.style.setProperty('cursor', 'grabbing', 'important');
      elmnt.classList.add('dragging');
      // calculate the new cursor position:
      pos1 = pos3 - e.clientX;
      pos2 = pos4 - e.clientY;
      pos3 = e.clientX;
      pos4 = e.clientY;
      // set the element's new position:
      //elmnt.style.top = (elmnt.offsetTop - pos2) + "px"; // Commented so the drag only goes side-to-side, not up-down.
      // TODO: Make sure the floater doesn't end up outside the window post-window-resize.
      elmnt.style.left = (elmnt.offsetLeft - pos1) + "px";
    }

    function closeDragElement(e) {
      // Stop moving when mouse button is released:
      e.preventDefault();
      e.stopPropagation();
      e.stopImmediatePropagation();
      document.onmouseup = null;
      document.onmousemove = null;
      document.body.style.cursor = "";
      elmnt.classList.remove('dragging');
      window.localStorage.setItem('guided-tour-floater-position-x', elmnt.style.left);
    }
  }

  utils.getTourData().then((data) => {
    console.info(data);
    const groups = data['groups'];
    // TODO: Maybe re-enable this and improve the functionality.
    // dragElement(document.querySelector('.draggable'));
    for (group in groups) {
      let groupEl = document.createElement('section');
      groupEl.setAttribute('data-gid', group);
      groupEl.classList.add('tour-section');
      if (window.localStorage.getItem('tour_95_' + utils.escapeTourName(groupEl['dataset'].gid) + '_TourFloaterTourCollapsed') == 'true') {
        groupEl.classList.add('collapsed');
      }
      console.debug(groups[group])
      // FIXME: Add HTML escapes (maybe use purify?)
      groupEl.innerHTML = '<div class="tour-header"><i class="fa-solid fa-chevron-right chevron"></i>' + groups[group]['displayTitle'] + '</div><div class="tour-content"></div>';
      // Chevron collapse section.
      groupEl.getElementsByClassName('tour-header')[0].onclick = (event) => {
        const contentElement = event.target.closest('.tour-section');
        window.localStorage.setItem('tour_95_' + utils.escapeTourName(contentElement['dataset'].gid) + '_TourFloaterTourCollapsed', contentElement.classList.toggle('collapsed'));
      };
      // TODO: Replace divs with actual ARIA/WCAG stuff, ul, etc
      groups[group]['tasks'].forEach(task => {
        if (!task.raw.isActive || task.raw.isHidden) {
          return;
        }
        let taskEl = document.createElement('div');
        taskEl.innerHTML = '<button class="pre-btn"><i class="fa fa-arrow-right"></i></button>' + task['title'] + '<button class="post-btn"><i class="fa fa-rotate-right"></i></button>';
        taskEl.setAttribute('data-id', task['id']);
        taskEl.className = 'tour-task';
        if (task['done']) {
          taskEl.classList.add('task-done')
        }
        groupEl.querySelector('.tour-content').appendChild(taskEl);
      });
      if (groupEl.querySelector('.tour-content').childElementCount > 0) {
        document.querySelector('.guides-container').appendChild(groupEl);
      }
    }
  });
});

/** Driver.js **/

.driver-overlay {
  pointer-events: none;
}

.driver-active:has(.driver-overlay) * {
  pointer-events: auto;
}

.driver-overlay.hideoy {
  opacity: 0%;
  transition: opacity animate-fade-in 200ms ease-in-out;
}

.driver-active .driver-overlay {
  pointer-events: none;
}

.driver-active .driver-active-element,
.driver-active .driver-active-element *,
.driver-popover,
.driver-popover * {
  pointer-events: auto;
}

@keyframes animate-fade-in {
  0% {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

.driver-fade .driver-overlay {
  animation: animate-fade-in 200ms ease-in-out;
}

.driver-fade .driver-popover {
  animation: animate-fade-in 200ms;
}

/* Popover styles */
.driver-popover {
  all: unset;
  box-sizing: border-box;
  color: #2d2d2d;
  margin: 0;
  padding: 15px;
  border-radius: 5px;
  min-width: 250px;
  max-width: 300px;
  box-shadow: 0 1px 10px #0006;
  z-index: 1000000000;
  position: fixed;
  top: 0;
  right: 0;
  background-color: #fff;
}

.driver-popover-title {
  font: 19px / normal sans-serif;
  font-weight: 700;
  display: block;
  position: relative;
  line-height: 1.5;
  zoom: 1;
  margin: 0;
}

.driver-popover-close-btn {
  all: unset;
  position: absolute;
  top: 0;
  right: 0;
  width: 32px;
  height: 28px;
  cursor: pointer;
  font-size: 18px;
  font-weight: 500;
  color: #d2d2d2;
  z-index: 1;
  text-align: center;
  transition: color;
  transition-duration: 200ms;
}

.driver-popover-close-btn:hover,
.driver-popover-close-btn:focus {
  color: #2d2d2d;
}

.driver-popover-title[style*="block"] + .driver-popover-description {
  margin-top: 5px;
}

.driver-popover-description {
  margin-bottom: 0;
  font: 14px / normal sans-serif;
  line-height: 1.5;
  font-weight: 400;
  zoom: 1;
}

.driver-popover-footer {
  margin-top: 15px;
  text-align: right;
  zoom: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.driver-popover-progress-text {
  font-size: 13px;
  font-weight: 400;
  color: #727272;
  zoom: 1;
}

.driver-popover-footer button {
  all: unset;
  display: inline-block;
  box-sizing: border-box;
  padding: 3px 7px;
  text-decoration: none;
  text-shadow: 1px 1px 0 #fff;
  background-color: #ffffff;
  color: #2d2d2d;
  font: 12px / normal sans-serif;
  cursor: pointer;
  outline: 0;
  zoom: 1;
  line-height: 1.3;
  border: 1px solid #ccc;
  border-radius: 3px;
}

.driver-popover-footer .driver-popover-btn-disabled {
  opacity: 0.5;
  pointer-events: none;
}

/* Disable the scrolling of parent element if it has an active element*/
:not(body):has(> .driver-active-element:not(body)) {
  overflow: hidden !important;
}

.driver-no-interaction, .driver-no-interaction * {
  pointer-events: none !important;
}

.driver-popover-footer button:hover,
.driver-popover-footer button:focus {
  background-color: #f7f7f7;
}

.driver-popover-navigation-btns {
  display: flex;
  flex-grow: 1;
  justify-content: flex-end;
}

.driver-popover-navigation-btns button + button {
  margin-left: 4px;
}

.driver-popover-arrow {
  content: "";
  position: absolute;
  border: 5px solid #fff;
}

.driver-popover-arrow-side-over {
  display: none;
}

/** Popover Arrow Sides **/
.driver-popover-arrow-side-left {
  left: 100%;
  border-right-color: transparent;
  border-bottom-color: transparent;
  border-top-color: transparent;
}

.driver-popover-arrow-side-right {
  right: 100%;
  border-left-color: transparent;
  border-bottom-color: transparent;
  border-top-color: transparent;
}

.driver-popover-arrow-side-top {
  top: 100%;
  border-right-color: transparent;
  border-bottom-color: transparent;
  border-left-color: transparent;
}

.driver-popover-arrow-side-bottom {
  bottom: 100%;
  border-left-color: transparent;
  border-top-color: transparent;
  border-right-color: transparent;
}

.driver-popover-arrow-side-center {
  display: none;
}

/* Left/Start + Right/Start */
.driver-popover-arrow-side-left.driver-popover-arrow-align-start,
.driver-popover-arrow-side-right.driver-popover-arrow-align-start {
  top: 15px;
}

/* Top/Start + Bottom/Start */
.driver-popover-arrow-side-top.driver-popover-arrow-align-start,
.driver-popover-arrow-side-bottom.driver-popover-arrow-align-start {
  left: 15px;
}

/* End/Left + End/Right */
.driver-popover-arrow-align-end.driver-popover-arrow-side-left,
.driver-popover-arrow-align-end.driver-popover-arrow-side-right {
  bottom: 15px;
}

/* Top/End + Bottom/End */
.driver-popover-arrow-side-top.driver-popover-arrow-align-end,
.driver-popover-arrow-side-bottom.driver-popover-arrow-align-end {
  right: 15px;
}

/* Left/Center + Right/Center */
.driver-popover-arrow-side-left.driver-popover-arrow-align-center,
.driver-popover-arrow-side-right.driver-popover-arrow-align-center {
  top: 50%;
  margin-top: -5px;
}

/* Top/Center + Bottom/Center */
.driver-popover-arrow-side-top.driver-popover-arrow-align-center,
.driver-popover-arrow-side-bottom.driver-popover-arrow-align-center {
  left: 50%;
  margin-left: -5px;
}

/* No arrow */
.driver-popover-arrow-none {
  display: none;
}

.guided-tour-floater {
  z-index: 999;
  position: fixed;
  bottom: 0px;
  right: 0px;
  box-shadow: 0px 0px 12px 0px #00000033;
  background-color: white;
  width: fit-content;
  overflow: hidden;
  display: inline-block;
  border-start-start-radius: 8px;
  user-select: none;
}

.guided-tour-floater.collapsed .top-bar {
  padding: 8px;
}

.guided-tour-floater.collapsed .icon {
  width: 0;
}

.guided-tour-floater .tour-section.collapsed .tour-content {
  max-height: 0;
}

.guided-tour-floater.collapsed .guides-content {
  width: 0;
  max-height: 0;
}

.guided-tour-floater.dragging * {
  pointer-events: none;
}

.guided-tour-floater.collapsed:not(.dragging) .header {
  cursor: pointer;
}

.guided-tour-floater.collapsed .header {
  padding: 0;
}

.guided-tour-floater.collapsed .right-group button:first-child {
  display: none;
}

.guided-tour-floater.collapsed .completeness {
  margin: 0;
  height: 4px;
  border-start-start-radius: 0;
  border-start-end-radius: 0;
  border-end-start-radius: 0;
  border-end-end-radius: 0;
}

.guided-tour-floater .header {
  display: inline-block;
  user-select: none;
  padding: 14px 16px 14px 16px;
}

.tour-header {
  font-weight: bold;
}

.guided-tour-floater .top-bar {
  display: flex;
  cursor: pointer;
}

.guided-tour-floater .icon {
  align-self: flex-start;
  margin-right: 0.5em;
  overflow: hidden;
  width: 30px;
}

.guided-tour-floater .title {
  align-self: flex-start;
  width: 100%;
  font-weight: bold;
}

.guided-tour-floater * {
  transition: max-height 0.45s cubic-bezier(.25, 1, .25, 1); /*, width 0.45s ease-in-out 0s*/
}

.guided-tour-floater .right-group {
  align-self: flex-end;
  white-space: nowrap;
  margin-left: 0.5em;
}

.guided-tour-floater .guides-content {
  display: flex;
  max-height: 400px;
  flex-direction: column;
  overflow: hidden;
}

.guided-tour-floater .guides-container {
  overflow-x: scroll;
  padding: 0px 16px 14px 16px;
  height: 100%;
}

.guided-tour-floater h2 {
  margin: 0em;
  padding-bottom: 0.5em;
}

/* .guided-tour-floater section::after {
content: "";
display: block;
border-top: 1px solid black;
border-bottom: 1px solid black;
Adjust color and thickness as needed
padding: 0.5em;
margin: 0.5em;
} */

.guided-tour-floater .useful-link {
  padding: 14px 16px 14px 16px;
  border-color: #ddddddFF;
  border-width: 1px;
  border-style: solid;
}

.guided-tour-floater .tour-task {
  /* Use subgrid for this */
  border-radius: 0.65em;
  transition: background-color 0.1s ease;
  padding: 0.5em;
  cursor: pointer;
}
.guided-tour-floater .tour-task.task-done {
  text-decoration: line-through;
}

.guided-tour-floater .tour-header {
  /* Use subgrid for this */
  cursor: pointer;
  border-radius: 0.65em;
  transition: background-color 0.1s ease;
  padding: 0.5em;
}

.guided-tour-floater .tour-section .chevron {
  cursor: pointer;
  display: inline-block;
  height: 16px;
  width: 16px;
  rotate: 0deg;
}

.guided-tour-floater .tour-section:not(.collapsed) .chevron {
  rotate: 90deg;
}

.guided-tour-floater .tour-header:hover {
  background: #f2f2f2FF 100%;
  /* Display restart button. */
}

.guided-tour-floater .tour-task:hover {
  background: #f2f2f2FF 100%;
  /* Display restart button. */
}

.guided-tour-floater .completeness {
  margin: 16px 0 16px 0;
  height: 9px;
  position: relative;
  width: 100%;
  background: #f2f2f2FF;
  border-start-start-radius: 18px;
  border-start-end-radius: 18px;
  border-end-start-radius: 18px;
  border-end-end-radius: 18px;
  overflow: hidden;
  flex-shrink: 0;
}
.guided-tour-floater.collapsed .completeness-progress {
  height: 4px;
}
.guided-tour-floater .completeness-progress {
  position: absolute;
  left: 0px;
  top: 0px;
  height: 9px;
  background: #7698ffFF;
}

.guided-tour-floater .tour-content {
  overflow: hidden;
  max-height: 300px;
}

/* ===== TOUR HEADER ===== */
.tour-header {
  display: flex;
  align-items: center;
  gap: 10px;
  cursor: pointer;
}

.tour-header .chevron {
  width: 20px;           /* fixed column */
  text-align: center;
  flex-shrink: 0;
  transition: transform 0.2s ease;
}

/* ===== TOUR TASKS ===== */
.tour-task {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 6px 0;
}


.tour-task {
  display: flex;
  align-items: center;
  gap: 10px;
}

.pre-btn,
.post-btn {
  width: 20px;
  flex-shrink: 0;
  background: none;
  border: none;
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.15s ease;
}

.post-btn {
  margin-left: auto;
}

.tour-task:hover .pre-btn,
.tour-task:hover .post-btn {
  opacity: 1;
}
